sp_widget.css:
.image-background{
  position:fixed;
  top:65px;
  left:0;
  height: 100%; /* You must set a specified height */
  background-position: center !important; /* Center the image */
  background-attachment: fixed;
  background-repeat:no-repeat;
  background-size:cover !important;
  opacity:.7;
  z-index:-5;
}

.sw-campaign-full-page-detail-container{
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-around;
  row-gap: 5rem;

  .detail-body-container{
    display: flex;
    flex-direction: column;
    align-items: center;
    row-gap: 2rem;
    font-size: 1.8rem;

    .session-tabs-container{
      width: 100%;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 2rem;
      column-gap: 10rem;

      .active-tab{
        font-weight: bold;
        text-decoration: underline;
      }
    }
  }
}

sp_widget.script:
(function() {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */
try{
	var table = $sp.getParameter('table');
	data.isSessionNote = table == 'x_176383_star_wars_session_plan' ? true : false;
	var sys_id = $sp.getParameter('sys_id');
	var util = new starWarsGMUtil();
	data.record = util.getFullPageCampaignDetail(table, sys_id);
} catch(e){
	console.log('full page campaign detail error: ' + e.message);
}
})();
